### 3. 实现 Token 服务

```typescript
// src/auth/token.service.ts
import jwt from 'jsonwebtoken';
import { v4 as uuidv4 } from 'uuid';
import { authConfig } from './auth.config';
import { redisClient } from '../redis/client';

export class TokenService {
  // 生成 access token
  generateAccessToken(userId: string, role: string): string {
    return jwt.sign(
      { sub: userId, role, type: 'access' },
      authConfig.accessToken.secret,
      { expiresIn: authConfig.accessToken.expiresIn }
    );
  }

  // 生成 refresh token
  async generateRefreshToken(userId: string): Promise<string> {
    const tokenId = uuidv4();
    const token = jwt.sign(
      { sub: userId, tokenId, type: 'refresh' },
      authConfig.refreshToken.secret,
      { expiresIn: authConfig.refreshToken.expiresIn }
    );

    // 存储 tokenId 到 Redis, 用于验证和撤销
    await redisClient.set(
      `refresh:${tokenId}`,
      userId,
      'EX',
      7 * 24 * 60 * 60 // 7天
    );

    return token;
  }

  // 验证 access token
  verifyAccessToken(token: string): { userId: string; role: string } | null {
    try {
      const decoded = jwt.verify(token, authConfig.accessToken.secret) as any;
      if (decoded.type !== 'access') return null;
      return { userId: decoded.sub, role: decoded.role };
    } catch {
      return null;
    }
  }

  // 验证 refresh token
  async verifyRefreshToken(token: string): Promise<string | null> {
    try {
      const decoded = jwt.verify(token, authConfig.refreshToken.secret) as any;
      if (decoded.type !== 'refresh') return null;

      // 检查是否在黑名单中
      const isBlacklisted = await redisClient.get(`blacklist:${decoded.tokenId}`);
      if (isBlacklisted) return null;

      // 验证 tokenId 是否有效
      const storedUserId = await redisClient.get(`refresh:${decoded.tokenId}`);
      if (!storedUserId || storedUserId !== decoded.sub) return null;

      return decoded.sub;
    } catch {
      return null;
    }
  }

  // 撤销 refresh token
  async revokeRefreshToken(token: string): Promise<void> {
    try {
      const decoded = jwt.decode(token) as any;
      if (decoded?.tokenId) {
        // 加入黑名单, 过期时间与 token 一致
        await redisClient.set(
          `blacklist:${decoded.tokenId}`,
          'revoked',
          'EX',
          7 * 24 * 60 * 60
        );
        // 删除原始记录
        await redisClient.del(`refresh:${decoded.tokenId}`);
      }
    } catch {
      // 静默失败
    }
  }

  // 刷新 token 对
  async refreshTokens(refreshToken: string): Promise<{
    accessToken: string;
    refreshToken: string;
  } | null> {
    const userId = await this.verifyRefreshToken(refreshToken);
    if (!userId) return null;

    // 撤销旧 refresh token
    await this.revokeRefreshToken(refreshToken);

    // 生成新的 token 对
    const newAccessToken = this.generateAccessToken(userId, 'user');
    const newRefreshToken = await this.generateRefreshToken(userId);

    return {
      accessToken: newAccessToken,
      refreshToken: newRefreshToken,
    };
  }
}
```

### 4. 实现认证中间件

```typescript
// src/auth/auth.middleware.ts
import { Request, Response, NextFunction } from 'express';
import { TokenService } from './token.service';

const tokenService = new TokenService();

// 扩展 Request 类型
declare global {
  namespace Express {
    interface Request {
      user?: {
        userId: string;
        role: string;
      };
    }
  }
}

// 认证中间件
export function authenticate(req: Request, res: Response, next: NextFunction) {
  const authHeader = req.headers.authorization;
  if (!authHeader?.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Missing or invalid authorization header' });
  }

  const token = authHeader.split(' ')[1];
  const payload = tokenService.verifyAccessToken(token);

  if (!payload) {
    return res.status(401).json({ error: 'Invalid or expired access token' });
  }

  req.user = payload;
  next();
}

// 角色验证中间件
export function requireRole(...roles: string[]) {
  return (req: Request, res: Response, next: NextFunction) => {
    if (!req.user || !roles.includes(req.user.role)) {
      return res.status(403).json({ error: 'Insufficient permissions' });
    }
    next();
  };
}
```

